// src/pages/vendor/VendorPortal.jsx
import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { KPI } from '../../components/UI';
import ComplaintCard from '../../components/ComplaintCard';
import { CLEANERS } from '../../data/mockData';

export default function VendorPortal() {
  const { complaints, updateComplaint } = useApp();
  const [activeTab, setActiveTab] = useState('TASKS');
  const [modalTask, setModalTask] = useState(null);

  const myVendorId = 'v1';
  const kpiNew = complaints.filter(c => c.status === 'NEW').length;
  const kpiActive = complaints.filter(c => ['ACCEPTED', 'IN_PROGRESS'].includes(c.status)).length;
  const kpiDone = complaints.filter(c => c.status === 'COMPLETED').length;

  const handleAccept = (id) => updateComplaint(id, { status: 'ACCEPTED', cleanerStatus: 'ASSIGNED' });
  
  const executeAssignment = (cleaner) => {
    if (!modalTask) return;
    updateComplaint(modalTask.id, {
      assignedTo: cleaner.name,
      status: 'IN_PROGRESS',
      cleanerStatus: 'CLEANING',
      vendor: { id: myVendorId, name: 'CleanRail Nagpur Services' }
    });
    setModalTask(null);
  };

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'sans-serif' }}>
      <Sidebar 
        title="Vendor Control Matrix" subtitle="Nagpur Clean Desk"
        navItems={[{ key: 'TASKS', label: 'Incoming Alerts Ledger', icon: '📋', count: kpiNew }]} activeTab={activeTab} onTabChange={setActiveTab}
        footerUser={{ name: 'Operations Executive', role: 'Nagpur Ground Head', initials: 'NG', avatarColor: '#004D40' }}
      />

      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: 20 }}>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 14, marginBottom: 20 }}>
          <KPI title="PENDING REDRESSAL" value={kpiNew} color="#E65100" />
          <KPI title="LIVE SWEEPS DRILL" value={kpiActive} color="#1565C0" />
          <KPI title="ARCHIVED HISTORY" value={kpiDone} color="#2E7D32" />
        </div>

        <div style={{ flex: 1, overflowY: 'auto', display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: 16, alignItems: 'start' }}>
          {complaints.map(c => (
            <ComplaintCard key={c.id} complaint={c} onAccept={handleAccept} onAssign={setModalTask} />
          ))}
        </div>
      </div>

      {modalTask && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 10000 }}>
          <div style={{ background: '#fff', padding: 20, borderRadius: 12, width: 320 }}>
            <h4 style={{ margin: '0 0 12px 0' }}>Deploy Field Sweeper Force</h4>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {CLEANERS.map(cleaner => (
                <button key={cleaner.id} onClick={() => executeAssignment(cleaner)} style={{ width: '100%', padding: 10, background: '#F7F9FC', border: '1px solid #DDE3E9', borderRadius: 8, cursor: 'pointer', textAlign: 'left', fontWeight: 600 }}>
                  🏃‍♂️ {cleaner.name} ({cleaner.area})
                </button>
              ))}
              <button onClick={() => setModalTask(null)} style={{ marginTop: 8, border: 'none', background: 'transparent', color: '#7A8FA6', cursor: 'pointer', fontWeight: 'bold', width: '100%' }}>Cancel Deployment</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
